<?php
namespace App\Http\Controllers;
use App\Models\SeoItem;
class PublicSeoController extends Controller{public function home(){$item=SeoItem::where('path','/')->firstOrFail();return view('seo-public',compact('item'));}public function listing($kind){$type=['blog'=>'blog','offres'=>'offer','realisations'=>'realization'][$kind]??'blog';$title=['blog'=>'Blog','offer'=>'Offres','realization'=>'Réalisations'][$type];$items=SeoItem::where('type',$type)->where('status','published')->latest()->get();$item=new SeoItem(['type'=>'page','title'=>$title,'path'=>'/'.$kind,'seo_title'=>$title.' | JCC Constructeur','seo_description'=>'Liste publique SEO-ready pour '.$title.' avec rendu Laravel.','focus_keyword'=>$title,'robots'=>'index, follow','og_image'=>'/og.svg']);return view('seo-listing',compact('item','items'));}public function show($kind,$slug){$type=['blog'=>'blog','offres'=>'offer','realisations'=>'realization'][$kind]??'blog';$item=SeoItem::where('type',$type)->where('slug',$slug)->firstOrFail();return view('seo-public',compact('item'));}public function page($slug){$item=SeoItem::where('type','page')->where('slug',$slug)->firstOrFail();return view('seo-public',compact('item'));}}
